//! Config file watcher for hot reload
//!
//! Watches config.toml for changes and emits SwitchModel events
//! when the provider or model configuration changes.

use std::collections::HashMap;
use std::path::PathBuf;
use std::time::Duration;
use tokio::sync::mpsc;
use tokio::time::interval;

use crate::event::Event;

// Duplicated from runie_provider::Config to avoid circular dependency
#[derive(Debug, Clone, Default, serde::Deserialize)]
struct ModelsSection {
    default: Option<String>,
}

#[derive(Debug, Clone, Default, serde::Deserialize)]
struct Config {
    provider: Option<String>,
    model: Option<String>,
    #[serde(default)]
    models: ModelsSection,
    #[serde(default)]
    #[allow(dead_code)]
    model_providers: HashMap<String, serde_json::Value>,
}

impl Config {
    /// Load config from a specific path
    fn load_from(path: &PathBuf) -> Self {
        if !path.exists() {
            return Self::default();
        }
        match std::fs::read_to_string(path) {
            Ok(text) => toml::from_str(&text).unwrap_or_default(),
            Err(_) => Self::default(),
        }
    }

    fn default_model(&self) -> Option<&str> {
        self.models.default.as_deref().or(self.model.as_deref())
    }
}

/// Start a config file watcher that monitors for changes and emits SwitchModel events.
///
/// Returns a tokio::JoinHandle that can be used to stop the watcher.
///
/// The watcher:
/// - Polls the config file every 2 seconds
/// - Compares the provider/model with the last known values
/// - Emits SwitchModel events when they change
pub fn spawn_config_watcher(
    event_tx: mpsc::Sender<Event>,
    config_path: PathBuf,
) -> tokio::task::JoinHandle<()> {
    tokio::spawn(async move {
        // Track last known provider/model to detect changes
        let mut last_provider: Option<String> = None;
        let mut last_model: Option<String> = None;

        let mut poll_interval = interval(Duration::from_secs(2));

        loop {
            poll_interval.tick().await;

            // Load current config from the specified path
            let config = Config::load_from(&config_path);

            // Extract provider and model from config
            let current_provider = config.provider.clone().unwrap_or_else(|| "mock".to_string());
            let current_model = config.default_model().unwrap_or("echo").to_string();

            // Check if provider changed
            let provider_changed = match &last_provider {
                Some(prev) => prev != &current_provider,
                None => true, // First run, always report change
            };

            // Check if model changed
            let model_changed = match &last_model {
                Some(prev) => prev != &current_model,
                None => true, // First run, always report change
            };

            // Emit when provider or model changes from last known value
            if last_provider.as_ref() != Some(&current_provider) 
                || last_model.as_ref() != Some(&current_model) {
                let evt = Event::SwitchModel {
                    provider: current_provider.clone(),
                    model: current_model.clone(),
                };
                if event_tx.send(evt).await.is_err() {
                    // Channel closed, exit watcher
                    break;
                }
            }

            // Update tracking
            last_provider = Some(current_provider);
            last_model = Some(current_model);
        }
    })
}

/// Get the default config file path
pub fn config_path() -> PathBuf {
    dirs::home_dir()
        .unwrap_or_else(|| PathBuf::from("."))
        .join(".runie")
        .join("config.toml")
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use tempfile::tempdir;

    #[tokio::test]
    async fn config_watcher_detects_initial_change() {
        let dir = tempdir().unwrap();
        let config_path = dir.path().join("config.toml");

        // Create initial config with explicit provider/model
        fs::write(&config_path, r#"
provider = "openai"
model = "gpt-4"

[model_providers.openai]
type = "openai"
base_url = "https://api.openai.com"
api_key = "test"
"#).unwrap();

        let (tx, mut rx) = mpsc::channel::<Event>(10);

        // Spawn watcher
        let handle = spawn_config_watcher(tx, config_path.clone());

        // Wait for the watcher to pick up the initial config
        // Give it time to load and compare (2 poll intervals = 4 seconds)
        tokio::time::sleep(Duration::from_secs(4)).await;

        // Check that a SwitchModel event was emitted for initial load
        let evt = tokio::time::timeout(Duration::from_secs(1), rx.recv()).await;
        assert!(evt.is_ok(), "Should receive SwitchModel event");
        assert!(matches!(evt.unwrap(), Some(Event::SwitchModel { .. })));

        // Clean up
        handle.abort();
    }

    #[tokio::test]
    async fn config_watcher_parses_toml_changes() {
        let dir = tempdir().unwrap();
        let config_path = dir.path().join("config.toml");

        // Create initial config
        fs::write(&config_path, r#"
provider = "openai"
model = "gpt-4"

[model_providers.openai]
type = "openai"
base_url = "https://api.openai.com"
api_key = "test"
"#).unwrap();

        let (tx, mut rx) = mpsc::channel::<Event>(10);
        let handle = spawn_config_watcher(tx, config_path.clone());

        // Wait for initial load
        tokio::time::sleep(Duration::from_secs(4)).await;

        // Drain any initial events
        while rx.try_recv().is_ok() {}

        // Now change the config
        fs::write(&config_path, r#"
provider = "anthropic"
model = "claude-3"

[model_providers.anthropic]
type = "anthropic"
base_url = "https://api.anthropic.com"
api_key = "test"
"#).unwrap();

        // Wait for the watcher to detect the change
        tokio::time::sleep(Duration::from_secs(3)).await;

        let evt = tokio::time::timeout(Duration::from_secs(1), rx.recv()).await;
        assert!(evt.is_ok(), "Should receive SwitchModel event");

        if let Some(Some(Event::SwitchModel { provider, model })) = evt.ok() {
            assert_eq!(provider, "anthropic");
            assert_eq!(model, "claude-3");
        } else {
            panic!("Expected SwitchModel event");
        }

        handle.abort();
    }

    #[test]
    fn config_path_returns_expected_path() {
        let path = config_path();
        assert!(path.components().next().is_some(), "Path should not be empty");
        assert!(path.file_name().map_or(false, |n| n == "config.toml"), 
                "Path should end with config.toml");
    }

    #[test]
    fn config_load_parses_toml() {
        let dir = tempdir().unwrap();
        let config_path = dir.path().join("config.toml");

        // Write a config file
        fs::write(&config_path, r#"
provider = "test-provider"
model = "test-model"

[model_providers.test-provider]
type = "test"
base_url = "http://localhost"
api_key = "secret"
"#).unwrap();

        // Load the config
        let config = Config::load_from(&config_path);

        assert_eq!(config.provider, Some("test-provider".to_string()));
        assert_eq!(config.model, Some("test-model".to_string()));
        assert_eq!(config.default_model(), Some("test-model"));
    }

    #[test]
    fn config_load_defaults_when_missing() {
        let dir = tempdir().unwrap();
        let config_path = dir.path().join("nonexistent.toml");

        let config = Config::load_from(&config_path);

        assert_eq!(config.provider, None);
        assert_eq!(config.model, None);
        assert_eq!(config.default_model(), None);
    }

    #[test]
    fn config_load_uses_default_model_from_models_section() {
        let dir = tempdir().unwrap();
        let config_path = dir.path().join("config.toml");

        fs::write(&config_path, r#"
provider = "openai"
model = "gpt-3.5"

[models]
default = "gpt-4"

[model_providers.openai]
type = "openai"
base_url = "https://api.openai.com"
api_key = "test"
"#).unwrap();

        let config = Config::load_from(&config_path);

        // Should prefer models.default over top-level model
        assert_eq!(config.default_model(), Some("gpt-4"));
    }
}

//! Runie Core — State, Events, Update, UI Architecture
//!
//! Architecture (three layers):
//!   model     :: AppState, ChatMessage (source of truth)
//!   event     :: Event enum (all possible state transitions)
//!   update    :: State transitions (pure functions)
//!   ui        :: Elements, Transform (view layer)
//!   labels    :: Static text constants

pub mod model;
pub mod event;
pub mod update;
pub mod labels;
pub mod ui;
pub mod provider;
pub mod session;
pub mod input_history;
pub mod keybindings;
pub mod tokens;
pub mod file_refs;
pub mod fuzzy;
pub mod snapshot;
pub mod config_reload;
#[cfg(test)]
pub mod dsl;

#[cfg(test)]
mod tests;
#[cfg(test)]
mod file_refs_lookup_tests;

pub use model::{AppState, ChatMessage, Role};
pub use snapshot::Snapshot;
pub use session::{Session, save, load, list, delete};
pub use event::Event;
pub use labels::{
    THINKING_LOADING, thinking_with_time, thought_with_time, format_timestamp,
};
pub use ui::{Element, Feed, LazyCache};
pub use provider::{Message, Provider, ResponseChunk};
pub use tokens::{estimate_tokens, TokenTracker};
pub use file_refs::{FileRef, find_files, is_image_file, read_file_ref};
pub use input_history::{load_history, save_history, filter_history, search_history};
pub use keybindings::{load_keybindings, default_keybindings, parse_keybindings_json, event_from_name};

//! Model — Application State (mutable borrow, no cloning per event)
use crate::snapshot::Snapshot;
use crate::ui::elements::Element;


const SPINNER_CHARS: &[char] = &['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠹', '⠸', '⠴', '⠼'];
const SPINNER_FRAMES: u32 = 12;

/// A viewport into the element cache — elements plus how many
/// lines to skip from the top of the first element.
#[derive(Clone, Copy)]
pub struct VisibleRegion<'a> {
    pub elements: &'a [Element],
    pub skip_lines: usize,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum QueuedMessageKind {
    Steering,
    FollowUp,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum DeliveryMode {
    /// Each message triggers a separate LLM call
    OneAtATime,
    /// All queued messages delivered together in one LLM call
    All,
}

impl Default for DeliveryMode {
    fn default() -> Self {
        DeliveryMode::OneAtATime
    }
}

#[derive(Clone, Debug)]
pub struct QueuedMessage {
    pub content: String,
    pub kind: QueuedMessageKind,
}

#[derive(Clone)]
pub struct AppState {
    pub messages: Vec<ChatMessage>,
    pub input: String,
    /// Cursor position in input (0 = before first char)
    pub cursor_pos: usize,
    pub streaming: bool,
    pub scroll: usize,
    pub thinking_started_at: Option<std::time::Instant>,
    pub request_queue: std::collections::VecDeque<(String, String)>,
    pub message_queue: Vec<QueuedMessage>,
    /// How steering messages are delivered to the LLM
    pub steering_mode: DeliveryMode,
    /// How follow-up messages are delivered to the LLM
    pub follow_up_mode: DeliveryMode,
    pub next_id: u64,
    pub current_request_id: Option<String>,
    pub turn_started_at: Option<std::time::Instant>,
    pub current_tool_name: Option<String>,
    pub tool_started_at: Option<std::time::Instant>,
    pub intermediate_step_count: usize,
    pub animation_frame: u32,
    pub turn_active: bool,
    pub current_action: Option<String>,
    pub current_provider: String,
    pub current_model: String,

    /// Number of commands sent to agent but not yet completed
    pub inflight: usize,
    /// @-ref file lookup suggestions
    pub at_suggestions: Option<Vec<String>>,
    /// Selected index in @-ref suggestions
    pub at_selected: Option<usize>,
    /// Last @-ref query to avoid redundant filesystem calls
    pub last_at_query: Option<String>,
    /// Global collapse flag — when true, ALL thoughts/tools render collapsed.
    /// New elements automatically respect this setting.
    pub all_collapsed: bool,
    /// Cached index of last assistant message — O(1) lookup for append_response
    pub(crate) last_assistant_index: Option<usize>,
    pub(crate) thought_seq: u64,
    pub(crate) input_history: Vec<String>,
    pub(crate) history_pos: Option<usize>,
    pub(crate) undo_stack: Vec<(String, usize)>,
    pub(crate) redo_stack: Vec<(String, usize)>,
    pub input_flash: u8,
    pub placeholder: String,
    element_count: usize,
    elements_cache: Vec<Element>,
    line_counts: Vec<usize>,
    total_lines: usize,
    dirty: bool,
    message_gen: u64,
    cached_gen: u64,
}

impl Default for AppState {
    fn default() -> Self {
        Self {
            messages: Vec::new(), input: String::new(), cursor_pos: 0,
            streaming: false, scroll: 0, thinking_started_at: None,
            request_queue: std::collections::VecDeque::new(),
            message_queue: Vec::new(),
            steering_mode: DeliveryMode::OneAtATime,
            follow_up_mode: DeliveryMode::OneAtATime,
            next_id: 0,
            current_request_id: None, turn_started_at: None,
            current_tool_name: None, tool_started_at: None,
            intermediate_step_count: 0, animation_frame: 0,
            turn_active: false, current_action: None,
            current_provider: "mock".into(), current_model: "echo".into(),
            inflight: 0,
            at_suggestions: None, at_selected: None, last_at_query: None,
            all_collapsed: false, last_assistant_index: None, thought_seq: 0,
            input_history: Vec::new(), history_pos: None,
            undo_stack: Vec::new(), redo_stack: Vec::new(),
            input_flash: 0, placeholder: "Type a message to start...".into(),
            element_count: 0, elements_cache: Vec::new(),
            line_counts: Vec::new(), total_lines: 0,
            dirty: true, message_gen: 1, cached_gen: 0,
        }
    }
}

impl AppState {
    pub fn thinking_elapsed_secs(&self) -> Option<f64> {
        self.thinking_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn turn_elapsed_secs(&self) -> Option<f64> {
        self.turn_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn tool_elapsed_secs(&self) -> Option<f64> {
        self.tool_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    /// Braille spinner frame (12-frame cycle)
    pub fn spinner_frame(&self) -> char {
        SPINNER_CHARS[(self.animation_frame % SPINNER_FRAMES) as usize]
    }

    pub fn next_id(&mut self) -> String {
        let id = format!("req.{}", self.next_id);
        self.next_id += 1;
        id
    }

    pub(crate) fn mark_dirty(&mut self) {
        self.dirty = true;
    }

    pub(crate) fn messages_changed(&mut self) {
        self.message_gen = self.message_gen.wrapping_add(1);
        self.dirty = true;
    }

    pub fn cache_generation(&self) -> u64 {
        self.message_gen
    }

    /// Rebuild cache only when messages changed — O(n) but gated
    pub fn ensure_fresh(&mut self) {
        if self.dirty && self.message_gen != self.cached_gen {
            self.elements_cache = crate::ui::LazyCache::rebuild(self);
            self.element_count = self.elements_cache.len();
            self.line_counts = self.elements_cache.iter().map(|e| e.line_count()).collect();
            self.total_lines = self.line_counts.iter().sum();
            self.cached_gen = self.message_gen;
        }
        self.dirty = false;
    }

    /// Visible elements slice — O(1), zero allocation
    pub fn visible(&self, skip: usize, take: usize) -> &[Element] {
        if self.elements_cache.is_empty() {
            return &[];
        }
        let start = skip.min(self.element_count).min(self.elements_cache.len());
        let end = (start + take).min(self.element_count).min(self.elements_cache.len());
        &self.elements_cache[start..end]
    }

    pub fn count(&self) -> usize {
        self.element_count.max(self.elements_cache.len())
    }

    pub fn element_count(&self) -> usize {
        self.element_count
    }

    pub fn total_lines(&self) -> usize {
        self.total_lines
    }

    pub fn elements_cache(&self) -> &[Element] {
        &self.elements_cache
    }

    pub fn tick_animation(&mut self) {
        let mut changed = false;
        if self.turn_active {
            self.animation_frame = self.animation_frame.wrapping_add(1);
            changed = true;
        }
        if self.input_flash > 0 {
            self.input_flash -= 1;
            changed = true;
        }
        if changed {
            self.dirty = true;
        }
    }

    /// Build an immutable Snapshot for the render actor.
    /// The event loop calls this after ensure_fresh(); the render
    /// actor receives it via channel and draws without touching state.
    pub fn snapshot(&self) -> Snapshot {
        Snapshot {
            elements: self.elements_cache.clone(),
            line_counts: self.line_counts.clone(),
            total_lines: self.total_lines,
            input: self.input.clone(),
            cursor_pos: self.cursor_pos,
            hint_text: self.hint_text(),
            at_suggestions: self.at_suggestions.clone(),
            at_selected: self.at_selected,
            turn_active: self.turn_active,
            input_flash: self.input_flash,
            placeholder: self.placeholder.clone(),
            spinner_frame: self.spinner_frame(),
            scroll: self.scroll,
            turn_elapsed_secs: self.turn_elapsed_secs(),
            provider: self.current_provider.clone(),
            model: self.current_model.clone(),
            queue_count: self.message_queue.len() + self.request_queue.len(),
        }
    }

    pub fn is_dirty(&self) -> bool {
        self.dirty
    }

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.total_lines.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }

    pub fn visible_scroll(&self, visible_height: usize) -> VisibleRegion<'_> {
        if self.elements_cache.is_empty() || visible_height == 0 {
            return VisibleRegion { elements: &[], skip_lines: 0 };
        }

        let total = self.total_lines;
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);

        let viewport_end = total.saturating_sub(scroll);
        let viewport_start = viewport_end.saturating_sub(visible_height);

        let mut cum = 0usize;
        let mut start_idx = 0;
        let mut skip_lines = 0;

        for (i, count) in self.line_counts.iter().enumerate() {
            let next_cum = cum + count;
            if next_cum > viewport_start {
                start_idx = i;
                skip_lines = viewport_start.saturating_sub(cum);
                break;
            }
            cum = next_cum;
        }

        let mut end_idx = self.elements_cache.len();
        cum = 0;
        for (i, count) in self.line_counts.iter().enumerate() {
            cum += count;
            if cum >= viewport_end {
                end_idx = i + 1;
                break;
            }
        }

        VisibleRegion {
            elements: &self.elements_cache[start_idx..end_idx.min(self.elements_cache.len())],
            skip_lines,
        }
    }

    pub fn total_tokens(&self) -> usize {
        self.messages.iter().map(|m| crate::tokens::estimate_tokens(&m.content)).sum()
    }

    pub fn compact(&mut self, keep_recent_tokens: usize) -> String {
        let total = self.total_tokens();
        if total <= keep_recent_tokens {
            return format!("Session has {} tokens, no compaction needed", total);
        }
        let mut accumulated = 0usize;
        let mut cut_idx = 0usize;
        for (i, msg) in self.messages.iter().enumerate().rev() {
            accumulated += crate::tokens::estimate_tokens(&msg.content);
            if accumulated >= keep_recent_tokens {
                cut_idx = i;
                break;
            }
        }
        while cut_idx < self.messages.len() {
            match self.messages[cut_idx].role {
                Role::User | Role::Assistant => break,
                _ => cut_idx += 1,
            }
        }
        if cut_idx == 0 {
            return "Cannot compact: all messages are recent".to_string();
        }
        let removed_count = cut_idx;
        self.messages.drain(..cut_idx);
        let summary = format!("[Compacted: {} earlier messages removed, keeping ~{} tokens]", removed_count, keep_recent_tokens);
        self.messages.insert(0, ChatMessage {
            role: Role::System,
            content: summary.clone(),
            timestamp: now(),
            id: "compaction".to_string(),
        });
        self.messages_changed();
        summary
    }
}

pub fn now() -> f64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

#[derive(Clone, Debug, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
pub enum Role {
    User,
    Thought,
    Assistant,
    Tool,
    TurnComplete,
    System,
}

impl Role {
    pub fn as_str(&self) -> &'static str {
        match self {
            Role::User => "user",
            Role::Thought => "thought",
            Role::Assistant => "assistant",
            Role::Tool => "tool",
            Role::TurnComplete => "turn_complete",
            Role::System => "system",
        }
    }
}

#[derive(Clone, Debug, serde::Serialize, serde::Deserialize)]
pub struct ChatMessage {
    pub role: Role,
    pub content: String,
    pub timestamp: f64,
    pub id: String,
}

//! Runie Terminal — Non-blocking event loop with render actor
//!
//! Architecture (impossible to block by design):
//!   1. Event loop: single-threaded async, only async ops
//!   2. State: owned by event loop, mutable borrow per event
//!   3. Snapshot: immutable frame description (the UI DSL)
//!   4. Render actor: owns Terminal, receives Snapshots via channel
//!   5. If render is slow, old Snapshots are dropped — event loop never waits

mod keymap;

use crossterm::event::{EventStream, KeyModifiers};
use futures::StreamExt;
use ratatui::{backend::CrosstermBackend, Terminal};
use runie_agent::{AgentCommand, run_agent_turn};
use runie_core::{AppState, Event as CoreEvent, Snapshot, keybindings, config_reload};
use std::{collections::HashMap, io, time::Duration};
use tokio::sync::mpsc;

const ANIM_MS: u64 = 200;

struct Cleanup;

impl Drop for Cleanup {
    fn drop(&mut self) {
        let _ = crossterm::execute!(std::io::stdout(), crossterm::terminal::LeaveAlternateScreen);
        let _ = crossterm::terminal::disable_raw_mode();
    }
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() -> io::Result<()> {
    let _cleanup = Cleanup;
    let terminal = setup_terminal()?;
    let state = AppState::default();

    let (input_tx, input_rx) = mpsc::channel::<CoreEvent>(100);
    let (agent_tx, agent_rx) = mpsc::channel::<CoreEvent>(100);
    let (cmd_tx, cmd_rx) = mpsc::channel::<AgentCommand>(10);
    let (render_tx, render_rx) = mpsc::channel::<Snapshot>(1);

    let keybindings = keybindings::load_keybindings(&None);

    tokio::spawn(agent_loop(cmd_rx, agent_tx));
    tokio::spawn(input_reader(input_tx, keybindings));
    tokio::spawn(render_task(terminal, render_rx));
    tokio::spawn(config_reload::spawn_config_watcher(input_tx.clone(), config_reload::config_path()));

    event_loop(state, input_rx, agent_rx, cmd_tx, render_tx).await
}

fn setup_terminal() -> io::Result<Terminal<CrosstermBackend<std::io::Stdout>>> {
    crossterm::terminal::enable_raw_mode()?;
    crossterm::execute!(
        std::io::stdout(),
        crossterm::terminal::EnterAlternateScreen,
        crossterm::event::EnableBracketedPaste,
    )?;
    Terminal::new(CrosstermBackend::new(std::io::stdout()))
}

async fn render_task(
    mut terminal: Terminal<CrosstermBackend<std::io::Stdout>>,
    mut render_rx: mpsc::Receiver<Snapshot>,
) {
    while let Some(snap) = render_rx.recv().await {
        let _ = terminal.draw(|f| runie_tui::ui::draw_snapshot(f, &snap));
    }
}

async fn input_reader(input_tx: mpsc::Sender<CoreEvent>, bindings: HashMap<String, String>) {
    let mut reader = EventStream::new();
    while let Some(Ok(event)) = reader.next().await {
        if let Some(evt) = keymap::convert_event(&event, &bindings) {
            let is_quit = matches!(&evt, CoreEvent::Quit | CoreEvent::Reset);
            if input_tx.send(evt).await.is_err() { break; }
            if is_quit { break; }
        }
    }
}

async fn event_loop(
    mut state: AppState,
    mut input_rx: mpsc::Receiver<CoreEvent>,
    mut agent_rx: mpsc::Receiver<CoreEvent>,
    cmd_tx: mpsc::Sender<AgentCommand>,
    render_tx: mpsc::Sender<Snapshot>,
) -> io::Result<()> {
    let mut anim = tokio::time::interval(Duration::from_millis(ANIM_MS));

    // Initial draw so the user sees the app immediately, without waiting
    // for the first keyboard event.
    state.ensure_fresh();
    let _ = render_tx.try_send(state.snapshot());

    loop {
        tokio::select! {
            biased;

            Some(evt) = input_rx.recv() => {
                let was_submit = matches!(evt, CoreEvent::Submit);
                let was_followup = matches!(evt, CoreEvent::FollowUp);
                let was_quit = matches!(evt, CoreEvent::Quit | CoreEvent::Reset);
                state.update(evt);
                if was_submit || was_followup {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
                if was_quit {
                    return Ok(());
                }
            }

            Some(evt) = agent_rx.recv() => {
                let was_done = matches!(evt, CoreEvent::AgentDone { .. } | CoreEvent::AgentError { .. });
                state.update(evt);
                if was_done {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
            }

            _ = anim.tick() => {
                state.tick_animation();
            }
        }

        state.ensure_fresh();
        let snap = state.snapshot();
        if render_tx.try_send(snap).is_err() {
            // Render task is behind — old snapshot dropped, latest will draw
        }
    }
}

async fn agent_loop(mut cmd_rx: mpsc::Receiver<AgentCommand>, agent_tx: mpsc::Sender<CoreEvent>) {
    while let Some(cmd) = cmd_rx.recv().await {
        let agent_tx_clone = agent_tx.clone();
        let cmd_id = cmd.id.clone();

        let result = run_agent_turn(
            &cmd,
            |evt| {
                let tx = agent_tx_clone.clone();
                let _ = tx.try_send(evt);
            },
            5,
        ).await;

        if let Err(e) = result {
            let _ = agent_tx.send(CoreEvent::AgentError {
                id: cmd_id,
                message: format!("Agent error: {}", e),
            }).await;
        }
    }
}

async fn spawn_if_queued(state: &mut AppState, cmd_tx: &mpsc::Sender<AgentCommand>) {
    if let Some((content, id)) = state.peek_queue() {
        let content = content.clone();
        let id = id.clone();
        state.pop_queue();
        state.streaming = true;
        state.turn_active = true;
        state.inflight += 1;
        let _ = cmd_tx.send(AgentCommand {
            content,
            id,
            provider: state.current_provider.clone(),
            model: state.current_model.clone(),
        }).await;
    }
}

